import threading

def parallel_sum(numbers):
    def worker(numbers):
        return sum(numbers)

    num_threads = max(1, len(numbers) // 4)
    chunk_size = (len(numbers) + num_threads - 1) // num_threads
    chunks = [numbers[i*chunk_size:(i+1)*chunk_size] for i in range(num_threads)]

    results = []
    threads = []

    def thread_func(chunk):
        result = worker(chunk)
        with threading.Lock():
            results.append(result)

    for chunk in chunks:
        t = threading.Thread(target=thread_func, args=(chunk,))
        threads.append(t)
        t.start()

    for t in threads:
        t.join()

    return sum(results)

